// Helper function to search HS codes
export function searchHSCodes(query: string, limit: number = 50): HSCode[] {
  const normalizedQuery = query.toLowerCase().trim();
  
  // Check if query is a code pattern (starts with numbers)
  const isCodeSearch = /^\d/.test(normalizedQuery);
  
  return hsCodes
    .filter(code => {
      if (isCodeSearch) {
        return code.code.startsWith(normalizedQuery.replace(/\D/g, ''));
      }
      
      // Search in description
      if (code.description.toLowerCase().includes(normalizedQuery)) return true;
      
      // Search in keywords
      if (code.keywords?.some(kw => kw.toLowerCase().includes(normalizedQuery))) return true;
      
      // Search in examples
      if (code.examples?.some(ex => ex.toLowerCase().includes(normalizedQuery))) return true;
      
      return false;
    })
    .slice(0, limit);
}

// Get all codes for a specific chapter
export function getHSCodesByChapter(chapter: string): HSCode[] {
  return hsCodes.filter(code => code.chapter === chapter.padStart(2, '0'));
}

// Get chapter info
export function getHSChapter(chapter: string): HSChapter | undefined {
  return hsChapters.find(ch => ch.chapter === chapter.padStart(2, '0'));
}

// Calculate total codes
export const totalHSCodes = hsCodes.length;
export const totalHSChapters = hsChapters.length;
